# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class BankAccount:
    def __init__(self, name, balance=0.0):
        self.name = name
        self.balance = balance

    def deposit(self, amount):
        # Process a deposit transaction and update the account balance
        if amount > 0:
            self.balance += amount
        else:
            raise ValueError('Deposit amount must be positive')

    def withdrawal(self, amount):
        # Process a withdrawal transaction and update the account balance
        if 0 < amount <= self.balance:
            self.balance -= amount
        elif amount < 0:
            raise ValueError('Withdrawal amount must be positive')
        else:
            raise ValueError('Insufficient funds')